const MAX_LEN = parseInt($env.TELEGRAM_MAX_MESSAGE_LENGTH || '4000', 10);
let text = String($json.responseText || '');

function mdToHtml(md) {
  return md
    .replace(/^### (.*$)/gim, '<b>$1</b>\n')
    .replace(/^## (.*$)/gim, '<b>$1</b>\n')
    .replace(/^# (.*$)/gim, '<b>$1</b>\n')
    .replace(/\*\*(.*?)\*\*/gim, '<b>$1</b>')
    .replace(/\*(.*?)\*/gim, '<i>$1</i>')
    .replace(/`(.*?)`/gim, '<code>$1</code>')
    .replace(/^\s*[-*] (.*$)/gim, '\u2022 $1')
    .replace(/^\s*\d+\. (.*$)/gim, '$1')
    .replace(/\n/gim, '\n')
    .slice(0, MAX_LEN);
}

const htmlText = mdToHtml(text);
const parts = [];
if (htmlText.length > MAX_LEN) {
  let remaining = htmlText;
  while (remaining.length > 0) {
    let chunk = remaining.slice(0, MAX_LEN);
    const lastBreak = Math.max(chunk.lastIndexOf('\n'), chunk.lastIndexOf(' '), chunk.lastIndexOf('</b>') + 4);
    if (lastBreak > MAX_LEN * 0.7) chunk = chunk.slice(0, lastBreak);
    parts.push(chunk.trim());
    remaining = remaining.slice(chunk.length);
  }
} else {
  parts.push(htmlText);
}

return parts.map(p => ({ json: { ...$json, messageText: p, messageParts: parts } }));
